THE RISK:
{
 "id": "europe-share-arithmetic-ghost",
 "title": "The 'Europe ≈ 30%' hop is an arithmetic ghost — no source states it, and regional datapoints put Europe closer to 24%",
 "narrative": "The entire €320M chain multiplies GVR's $2.81B global figure by 'Europe ≈ 30%', a number no publisher states — it is inferred by eyeballing the residual after North America's 38%. But the only regional revenue datapoints in the corpus cut the other way: the US alone is $579.7M of a $2.1B global intelligent-PDU market (~28% for one country), APAC is uniformly described as the fastest-growing region, and Germany — half of the CE weight — is forecast to grow its intelligent-PDU segment at only 5.2–5.3%, roughly half the global rate. If PDU revenue is more NA/APAC-skewed than DC capacity, Europe sits at 22–25%, not 30%, and every downstream node inherits the error. This is not 'the band's low end' — it is a specific hop whose value was never observed, drifting in a specific direction.",
 "category": "fact",
 "targetNodes": [
  "tamBase"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "The 30% Europe multiplier in tamBase's derivation is unsourced: GVR states only NA = 38%, and no source found anywhere states a Europe rack-PDU revenue share",
   "refs": [
    "ledger:tamBase",
    "digest:tam-global-crosscheck#c1"
   ]
  },
  {
   "step": "propagation",
   "text": "Regional evidence skews the residual away from Europe: US intelligent-PDU market alone is $579.7M of $2.1B global (~28%), China is on a 6.4% CAGR toward $498M, and Germany's intelligent-PDU CAGR (5.2–5.3%) runs at roughly half the 9.7% global rack-PDU rate — meaning Europe's share is both lower than 30% and declining through the venture window",
   "refs": [
    "digest:tam-global-crosscheck#c15",
    "digest:tam-global-crosscheck#c13",
    "digest:tam-global-crosscheck#c14",
    "digest:tam-global-crosscheck#c0"
   ]
  },
  {
   "step": "model-impact",
   "text": "Europe at ~24% instead of 30% rescales the whole scope-down chain multiplicatively — the curated €320M point value sits above the recomputed primary derivation, and SAM/YAM shrink proportionally",
   "refs": [
    "ledger:tamBase"
   ]
  }
 ],
 "whyMissable": "The hop looks sourced because it sits inside a derivation expression quoting Grand View by name — the citation is real, but it covers only the NA share. A team auditing the ledger sees '[est.; NA = 38% per same source]' and reads it as a bracketed footnote, not as the single unobserved multiplier the entire funnel rests on.",
 "expectedObviousness": "medium",
 "falsifier": "Any primary source stating Europe's rack-PDU revenue share at ≥28% — e.g., the Omdia Rack PDU Annual Tracker regional table or the IndexBox EU Rack PDUs headline reconciled against GVR's global base.",
 "likelihood": {
  "value": 0.5,
  "rationale": "Every regional datapoint in the corpus (US intelligent-PDU absolute size, Germany's sub-global CAGR, APAC growth framing) points below 30%, but none directly measures the Europe rack-PDU share, so the direction is evidenced while the magnitude is not. [evidence revision: Corroborating regional evidence (US ~28% single-country, Germany at half global CAGR, APAC fastest-growing, NA fixed at 38%) consistently points below 30% for Europe, strengthening the directional claim modestly above the prior 0.4. But the precise ~24% magnitude remains unobserved — no source directly states Europe's rack-PDU share, and the potential falsifier (Omdia/IndexBox regional table) was inaccessible, so the value cannot be raised further.]",
  "basis": "evidence",
  "revisedFrom": 0.4
 },
 "perturbation": [
  {
   "nodeId": "tamBase",
   "op": "scale",
   "value": 0.8,
   "note": "Europe share 30% → ~24% of the global rack-PDU base"
  }
 ],
 "indicators": [
  {
   "signal": "Regional revenue split in the next Omdia Rack PDU Annual Market Analysis or GVR report edition",
   "where": "Omdia rack-PDU tracker (2025 update) regional tables; Grand View Research report refresh",
   "threshold": "Europe stated at <27% of global rack-PDU revenue",
   "updates": "increases"
  },
  {
   "signal": "EMEA vs Americas revenue mix for rack-power product lines in incumbent segment reporting",
   "where": "Vertiv 10-K segment disclosures; Legrand universe-by-region commentary in annual results",
   "threshold": "EMEA rack-power growth persistently below Americas by >4pp",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Commission the IndexBox EU Rack PDUs report ($4,000) to replace the inferred Europe share with a directly-scoped EU headline figure",
   "type": "information",
   "voiNodeId": "tamBase",
   "note": "Named in the ledger as the promotion path; collapses the unsourced 30% hop entirely"
  },
  {
   "action": "Rebuild tamBase bottom-up from CE energized MW × PDUs-per-rack × ASP, bypassing the global-share hop altogether",
